    .btn-danger { background:#dc2626;color:#fff;border:none;border-radius:var(--radius-sm);padding:.4rem .75rem;font-size:.8rem;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:.25rem;transition:background .15s; }
