    .cal-wrapper { overflow-x:auto; }
    .cal-grid {
        position:relative;
        display:grid;
        grid-template-columns:52px 1fr;
        min-width:400px;
    }
    .cal-time-col { position:relative; }
    .cal-time-slot {
        height: 45px;
        display:flex;
        align-items:flex-start;
        justify-content:flex-end;
        padding-right:10px;
        padding-top:0;
        font-size:.7rem;
        font-weight:600;
        color:var(--text-muted);
        box-sizing:border-box;
        margin-top:-1px;
        user-select:none;
    }
    .cal-event-col {
        position:relative;
        border-left:2px solid var(--border);
    }
    .cal-hour-line {
        position:absolute;
        left:0; right:0;
        border-top:1px solid var(--border);
        height:0;
    }
    .cal-half-line {
        position:absolute;
        left:0; right:0;
        border-top:1px dashed #e2e8f0;
        height:0;
    }
    /* Punch boundary shading */
    .cal-before-punch, .cal-after-punch {
        position:absolute;
        left:0; right:0;
        background:repeating-linear-gradient(
            45deg,
            transparent,
            transparent 4px,
            rgba(0,0,0,.03) 4px,
            rgba(0,0,0,.03) 8px
        );
        pointer-events:none;
        z-index:1;
    }
    .cal-punch-line {
        position:absolute;
        left:0; right:0;
        height:2px;
        z-index:2;
    }
    .cal-punch-in-line  { background:#16a34a; }
    .cal-punch-out-line { background:#dc2626; }
    .cal-punch-label {
        position:absolute;
        right:8px;
        font-size:.65rem;
        font-weight:700;
        padding:1px 5px;
        border-radius:3px;
        z-index:3;
        pointer-events:none;
    }
    .cal-punch-label-in  { background:#16a34a;color:#fff; }
    .cal-punch-label-out { background:#dc2626;color:#fff; }

    /* Drag selection preview */
    .cal-drag-preview {
        position:absolute;
        left:4px; right:4px;
        background:rgba(19,127,236,.2);
        border:2px dashed var(--primary);
        border-radius:4px;
        pointer-events:none;
        z-index:10;
        display:none;
    }

    /* Work entry blocks */
    .cal-entry {
        position:absolute;
        left:4px; right:4px;
        border-radius:6px;
        padding:4px 8px;
        cursor:pointer;
        overflow:hidden;
        z-index:5;
        box-shadow:0 1px 3px rgba(0,0,0,.12);
        transition:box-shadow .12s, filter .12s;
        user-select:none;
    }
    .cal-entry:hover { box-shadow:0 3px 8px rgba(0,0,0,.2); filter:brightness(.96); }
    .cal-entry .entry-title { font-size:.75rem;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:#fff; }
    .cal-entry .entry-time  { font-size:.65rem;color:rgba(255,255,255,.85); }

    /* Entry colours (cycle through palette) */
    .entry-color-0 { background:linear-gradient(135deg,#137fec,#3b82f6); }
    .entry-color-1 { background:linear-gradient(135deg,#7c3aed,#a78bfa); }
    .entry-color-2 { background:linear-gradient(135deg,#059669,#34d399); }
    .entry-color-3 { background:linear-gradient(135deg,#d97706,#fbbf24); }
    .entry-color-4 { background:linear-gradient(135deg,#db2777,#f472b6); }
    .entry-color-5 { background:linear-gradient(135deg,#0891b2,#67e8f9); }

    /* Clickable time slots */
    .cal-click-zone {
        position:absolute;
        left:0; right:0;
        cursor:crosshair;
    }

