    .ts-modal-overlay { display:none;position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:1000;align-items:center;justify-content:center; }
    .ts-modal-overlay.open { display:flex; }
    .ts-modal { background:var(--surface);border-radius:var(--radius-md);box-shadow:var(--shadow-lg);width:100%;max-width:480px;max-height:90vh;overflow-y:auto;margin:1rem; }
    .ts-modal-header { padding:1rem 1.25rem;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between; }
    .ts-modal-header h4 { font-size:.9375rem;font-weight:700;margin:0; }
    .ts-modal-close { background:none;border:none;font-size:1.3rem;cursor:pointer;color:var(--text-muted);line-height:1;padding:.2rem; }
    .ts-modal-body { padding:1.25rem; }
    .form-group { margin-bottom:1rem; }
    .form-group label { display:block;font-size:.8rem;font-weight:600;color:var(--text-secondary);margin-bottom:.35rem; }
    .form-control { width:100%;padding:.55rem .75rem;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:.875rem;color:var(--text-main);background:var(--surface);transition:border-color .15s,box-shadow .15s;box-sizing:border-box; }
    .form-control:focus { outline:none;border-color:var(--primary);box-shadow:0 0 0 3px var(--primary-subtle); }
    .form-control.is-invalid { border-color:#ef4444; }
    .invalid-feedback { font-size:.78rem;color:#dc2626;margin-top:.3rem; }
    .modal-error { background:#fff1f2;color:#dc2626;border:1px solid #fecaca;border-radius:var(--radius-sm);padding:.625rem .875rem;font-size:.8375rem;margin-bottom:1rem;display:none; }
