                        {{-- Events Column --}}
                        @php $totalSlots = $gridMeta['total_minutes']; @endphp
                        <div class="cal-event-col" id="calEventCol"
                             style="height:{{ $totalSlots * $ppm }}px;">

                            {{-- Slot lines --}}
                            @for($offset = 0; $offset <= $totalSlots; $offset += $slotMinutes)
                                <div class="cal-hour-line" style="top:{{ $offset * $ppm }}px;"></div>
                            @endfor

                            {{-- Punch boundaries --}}
                            @if($punchIn)
                            @php
                                [$piH, $piM] = explode(':', $punchIn);
                                $piMinutes = (int)$piH * 60 + (int)$piM;
                                $piOffset  = ($piMinutes - $gridStartMinutes) * $ppm;
                            @endphp
                            @if($piOffset > 0)
                                <div class="cal-before-punch" style="top:0;height:{{ $piOffset }}px;"></div>
                            @endif
                            <div class="cal-punch-line cal-punch-in-line" style="top:{{ $piOffset }}px;"></div>
                            <div class="cal-punch-label cal-punch-label-in" style="top:{{ $piOffset - 14 }}px;">IN {{ $punchIn }}</div>
                            @endif

                            @if($punchOut)
                            @php
                                [$poH, $poM] = explode(':', $punchOut);
                                $poMinutes = (int)$poH * 60 + (int)$poM;
                                $poOffset  = ($poMinutes - $gridStartMinutes) * $ppm;
                                $afterHeight = ($totalSlots - ($poMinutes - $gridStartMinutes)) * $ppm;
                            @endphp
                            <div class="cal-punch-line cal-punch-out-line" style="top:{{ $poOffset }}px;"></div>
                            <div class="cal-punch-label cal-punch-label-out" style="top:{{ $poOffset + 3 }}px;">OUT {{ $punchOut }}</div>
                            @if($afterHeight > 0)
                                <div class="cal-after-punch" style="top:{{ $poOffset }}px;height:{{ $afterHeight }}px;"></div>
                            @endif
                            @endif

                            {{-- Drag preview --}}
                            <div class="cal-drag-preview" id="dragPreview"></div>

                            {{-- Existing entries --}}
                            @foreach($timesheet->entries as $index => $entry)
                            @php
                                [$sh, $sm] = explode(':', $entry->start_time);
                                [$eh, $em] = explode(':', $entry->end_time);
                                $startMin = (int)$sh * 60 + (int)$sm;
                                $endMin   = (int)$eh * 60 + (int)$em;
                                $top      = ($startMin - $gridStartMinutes) * $ppm;
                                $height   = ($endMin - $startMin) * $ppm;
                                $colorIdx = $index % 6;
                            @endphp
                            <div class="cal-entry entry-color-{{ $colorIdx }}"
                                 id="entry-{{ $entry->getRouteKey() }}"
                                 style="top:{{ $top }}px;height:{{ max($height, 22) }}px;"
