<div class="ts-modal-overlay" id="entryModal" onclick="if(event.target===this)closeModal()">
    <div class="ts-modal">
        <div class="ts-modal-header">
            <h4 id="modalTitle">Add Work Entry</h4>
            <button class="ts-modal-close" onclick="closeModal()" aria-label="Close">&times;</button>
        </div>
        <div class="ts-modal-body">
            <div class="modal-error" id="modalError"></div>
            <input type="hidden" id="editEntryId" value="">

            <div class="form-group">
                <label for="entryTitle">Task Title <span style="color:#dc2626;">*</span></label>
                <input type="text" id="entryTitle" class="form-control" placeholder="e.g. CRM Module Development" maxlength="255" autocomplete="off">
                <div class="invalid-feedback" id="titleError"></div>
            </div>
            <div class="form-group">
                <label for="entryDescription">Description</label>
                <textarea id="entryDescription" class="form-control" rows="3" placeholder="Optional details about this work..." maxlength="2000"></textarea>
            </div>
            <div class="time-grid">
                <div class="form-group">
                    <label for="entryStart">Start Time <span style="color:#dc2626;">*</span></label>
                    <input type="time" id="entryStart" class="form-control" step="60" min="{{ $punchIn ?? '06:00' }}" max="{{ $punchOut ?? '23:00' }}">
                    <div class="invalid-feedback" id="startError"></div>
                </div>
                <div class="form-group">
                    <label for="entryEnd">End Time <span style="color:#dc2626;">*</span></label>
                    <input type="time" id="entryEnd" class="form-control" step="60" min="{{ $punchIn ?? '06:00' }}" max="{{ $punchOut ?? '23:00' }}">
                    <div class="invalid-feedback" id="endError"></div>
                </div>
            </div>
            <div id="durationPreview" style="font-size:.8rem;color:var(--text-muted);margin-top:-.5rem;margin-bottom:.5rem;"></div>
        </div>
        <div class="ts-modal-footer">
            <div>
                <button type="button" id="deleteEntryBtn" class="btn-danger" style="display:none;" onclick="deleteCurrentEntry()">
                    <span class="material-symbols-outlined" style="font-size:.9rem;">delete</span>Delete
                </button>
            </div>
            <div style="display:flex;gap:.5rem;">
                <button type="button" class="btn-outline" onclick="closeModal()">Cancel</button>
                <button type="button" class="btn-primary" id="saveEntryBtn" onclick="saveEntry()">
                    <span class="material-symbols-outlined" style="font-size:1rem;">save</span>
                    Save Entry
                </button>
            </div>
        </div>
    </div>
</div>

@endsection

@push('scripts')
<script>
(function () {
    const grid       = document.getElementById('calGrid');
    const eventCol   = document.getElementById('calEventCol');
    const dragPrev   = document.getElementById('dragPreview');
    const isEditable = grid.dataset.editable === '1';
    const gridStartMinutes = parseInt(grid.dataset.gridStartMinutes, 10);
    const gridEndMinutes   = parseInt(grid.dataset.gridEndMinutes, 10);
    const slotMinutes      = parseInt(grid.dataset.slotMinutes, 10);
    const ppm        = parseFloat(grid.dataset.ppm);
    const punchIn    = grid.dataset.punchIn  || null;
    const punchOut   = grid.dataset.punchOut || null;
    const storeUrl   = grid.dataset.storeUrl;
    const deleteBase = grid.dataset.deleteUrlBase;
    const csrf       = grid.dataset.csrf;

    // Current editing state
    let editingId   = null;
    let entryCount  = {{ $timesheet->entries->count() }};
    let totalMin    = {{ $timesheet->total_minutes }};
    let colorIndex  = entryCount % 6;

    // Entry data store (id -> object)
    const entries = {};
    @foreach($timesheet->entries as $idx => $entry)
    entries[@json($entry->getRouteKey())] = {
        id: @json($entry->getRouteKey()),
        title: @json($entry->title),
        description: @json($entry->description ?? ''),
        start_time: '{{ $entry->start_time }}',
        end_time:   '{{ $entry->end_time }}',
        duration_minutes: {{ $entry->duration_minutes }},
        colorIdx: {{ $idx % 6 }},
