    let dragStart = null, dragCurrent = null, isDragging = false;

    if (isEditable) {
        eventCol.addEventListener('mousedown', function (e) {
            if (e.button !== 0) return;
            if (e.target.classList.contains('cal-entry') || e.target.closest('.cal-entry')) return;
            const rect = eventCol.getBoundingClientRect();
            const y    = e.clientY - rect.top;
            dragStart  = pixelToMinutes(y);
            isDragging = false;
        });

        document.addEventListener('mousemove', function (e) {
            if (dragStart === null) return;
            const rect    = eventCol.getBoundingClientRect();
            const y       = e.clientY - rect.top;
            dragCurrent   = normalizeMinutes(pixelToMinutes(y));
            isDragging    = true;

            const start = Math.min(normalizeMinutes(dragStart), dragCurrent);
            const end   = Math.max(normalizeMinutes(dragStart), dragCurrent);
            if (end <= start) { dragPrev.style.display = 'none'; return; }

            dragPrev.style.top     = minutesToPixel(start) + 'px';
            dragPrev.style.height  = minutesToPixel(end - start) + 'px';
            dragPrev.style.display = 'block';
        });

        document.addEventListener('mouseup', function (e) {
            if (dragStart === null) return;
            if (isDragging && dragCurrent !== null) {
                const start = normalizeMinutes(Math.min(dragStart, dragCurrent));
                const end   = normalizeMinutes(Math.max(dragStart, dragCurrent));
                if (end > start) {
                    openNewModalWithTimes(minutesToTime(start + gridStartMinutes), minutesToTime(end + gridStartMinutes));
                }
            }
            dragStart   = null;
            dragCurrent = null;
            isDragging  = false;
            dragPrev.style.display = 'none';
        });

        // Click on empty slot
        eventCol.addEventListener('click', function (e) {
            if (isDragging) return;
            if (e.target.classList.contains('cal-entry') || e.target.closest('.cal-entry')) return;
            const rect  = eventCol.getBoundingClientRect();
            const y     = e.clientY - rect.top;
            const mins  = normalizeMinutes(pixelToMinutes(y));
            const start = minutesToTime(mins + gridStartMinutes);
            const end   = minutesToTime(Math.min(mins + gridStartMinutes + 60, gridEndMinutes));
            openNewModalWithTimes(start, end);
        });
    }

    function pixelToMinutes(px) { return Math.max(0, Math.min(px / ppm, gridEndMinutes - gridStartMinutes)); }
    function minutesToPixel(m)  { return m * ppm; }
    function normalizeMinutes(m) { return Math.round(m); }
    function minutesToTime(totalMins) {
        const h = Math.floor(totalMins / 60);
        const m = totalMins % 60;
        return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0');
    }
    function timeToMinutes(t) {
        const [h, m] = t.split(':').map(Number);
        return h * 60 + m;
    }

