    window.openNewModal = function () {
        const startMinutes = Math.max(punchIn ? timeToMinutes(punchIn) : gridStartMinutes, gridStartMinutes);
        openNewModalWithTimes(
            minutesToTime(startMinutes),
            minutesToTime(Math.min(startMinutes + 60, gridEndMinutes))
        );
    };

    window.openNewModalWithTimes = function (start, end) {
        editingId = null;
        document.getElementById('modalTitle').textContent     = 'Add Work Entry';
        document.getElementById('editEntryId').value          = '';
        document.getElementById('entryTitle').value           = '';
        document.getElementById('entryDescription').value     = '';
        document.getElementById('entryStart').value           = start;
        document.getElementById('entryEnd').value             = end;
        document.getElementById('deleteEntryBtn').style.display = 'none';
        clearErrors();
        updateDurationPreview();
        document.getElementById('entryModal').classList.add('open');
        setTimeout(() => document.getElementById('entryTitle').focus(), 50);
    };

    window.openEditModal = function (el) {
        if (!isEditable) return;
        const id  = el.dataset.entryId;
        const e   = entries[id];
        if (!e) return;
        editingId = id;
        document.getElementById('modalTitle').textContent     = 'Edit Work Entry';
        document.getElementById('editEntryId').value          = id;
        document.getElementById('entryTitle').value           = e.title;
        document.getElementById('entryDescription').value     = e.description || '';
        document.getElementById('entryStart').value           = e.start_time;
        document.getElementById('entryEnd').value             = e.end_time;
        document.getElementById('deleteEntryBtn').style.display = 'inline-flex';
        clearErrors();
        updateDurationPreview();
        document.getElementById('entryModal').classList.add('open');
        setTimeout(() => document.getElementById('entryTitle').focus(), 50);
    };

    window.openEditModalById = function (id) {
        const el = document.getElementById('entry-' + id);
        if (el) openEditModal(el);
    };

    window.closeModal = function () {
        document.getElementById('entryModal').classList.remove('open');
        editingId = null;
    };

    // Update duration preview as user types
    document.getElementById('entryStart').addEventListener('input', updateDurationPreview);
    document.getElementById('entryEnd').addEventListener('input', updateDurationPreview);

    function updateDurationPreview() {
        const s = document.getElementById('entryStart').value;
        const e = document.getElementById('entryEnd').value;
        if (!s || !e) { document.getElementById('durationPreview').textContent = ''; return; }
        const sm = timeToMinutes(s), em = timeToMinutes(e);
        if (em <= sm) { document.getElementById('durationPreview').textContent = 'End time must be after start time'; return; }
        
        const diff = em - sm;
        const h    = Math.floor(diff / 60), m = diff % 60;
        document.getElementById('durationPreview').textContent = 'Duration: ' + (h > 0 ? h + 'h ' : '') + (m > 0 ? m + 'm' : '');
    }

