    window.saveEntry = function () {
        clearErrors();
        const title = document.getElementById('entryTitle').value.trim();
        const desc  = document.getElementById('entryDescription').value.trim();
        const start = document.getElementById('entryStart').value;
        const end   = document.getElementById('entryEnd').value;

        if (!title) { showFieldError('titleError', 'Title is required.'); return; }
        if (!start) { showFieldError('startError', 'Start time is required.'); return; }
        if (!end)   { showFieldError('endError',   'End time is required.');   return; }
        if (timeToMinutes(end) <= timeToMinutes(start)) {
            showFieldError('endError', 'End time must be after start time.'); return;
        }
        

        const btn = document.getElementById('saveEntryBtn');
        btn.disabled = true;
        btn.innerHTML = '<span class="material-symbols-outlined" style="font-size:1rem;">hourglass_top</span> Saving...';

        const url    = editingId
            ? deleteBase + '/' + editingId
            : storeUrl;
        const method = editingId ? 'PUT' : 'POST';

        fetch(url, {
            method,
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-TOKEN': csrf,
                'Accept':       'application/json',
            },
            body: JSON.stringify({ title, description: desc || null, start_time: start, end_time: end }),
        })
        .then(async res => {
            const data = await res.json();
            if (!res.ok) {
                showModalError(data.error || data.message || 'An error occurred.');
                return;
            }
            handleEntrySaved(data, editingId);
            closeModal();
        })
        .catch(() => showModalError('Network error. Please try again.'))
        .finally(() => {
            btn.disabled = false;
            btn.innerHTML = '<span class="material-symbols-outlined" style="font-size:1rem;">save</span> Save Entry';
        });
    };

