    window.deleteCurrentEntry = function () {
        if (!editingId) return;
        if (!confirm('Delete this work entry?')) return;

        fetch(deleteBase + '/' + editingId, {
            method: 'DELETE',
            headers: { 'X-CSRF-TOKEN': csrf, 'Accept': 'application/json' },
        })
        .then(async res => {
            const data = await res.json();
            if (!res.ok) { showModalError(data.error || 'Could not delete.'); return; }
            removeEntryFromUI(editingId);
            updateTotals(data.total_minutes);
            closeModal();
        })
        .catch(() => showModalError('Network error.'));
    };

