    function handleEntrySaved(data, wasEditingId) {
        const e = data.entry;

        // Store in local registry
        const isNew = !wasEditingId;
        const idx   = isNew ? (colorIndex++ % 6) : entries[wasEditingId]?.colorIdx ?? 0;
        entries[e.id] = { ...e, colorIdx: idx };

        // Update or create DOM block on calendar
        if (isNew) {
            const block = makeEntryBlock(e, idx);
            eventCol.appendChild(block);
            entryCount++;
        } else {
            const existing = document.getElementById('entry-' + wasEditingId);
            if (existing) {
                const block = makeEntryBlock(e, idx);
                eventCol.replaceChild(block, existing);
            }
        }

        // Update sidebar list
        updateSidebarList(e, idx, isNew);
        updateTotals(data.total_minutes);
    }

    function makeEntryBlock(e, idx) {
        const [sh, sm] = e.start_time.split(':').map(Number);
        const [eh, em] = e.end_time.split(':').map(Number);
        const startMin = sh * 60 + sm;
        const endMin   = eh * 60 + em;
        const top      = (startMin - gridStartMinutes) * ppm;
        const height   = Math.max((endMin - startMin) * ppm, 22);

        const block = document.createElement('div');
        block.className = 'cal-entry entry-color-' + idx;
        block.id = 'entry-' + e.id;
        block.style.top    = top + 'px';
        block.style.height = height + 'px';
        block.dataset.entryId    = e.id;
        block.dataset.title      = e.title;
        block.dataset.description= e.description || '';
        block.dataset.start      = e.start_time;
        block.dataset.end        = e.end_time;
        block.dataset.duration   = e.duration_minutes;
        block.dataset.colorIdx   = idx;
        block.onclick = function () { openEditModal(this); };
        block.innerHTML = `<div class="entry-title">${htmlEsc(e.title)}</div><div class="entry-time">${e.start_time} - ${e.end_time} | ${e.formatted_duration}</div>`;
        return block;
    }

    function updateSidebarList(e, idx, isNew) {
        const listEl = document.getElementById('entriesList');
        const noMsg  = document.getElementById('noEntriesMsg');
        if (noMsg) noMsg.style.display = 'none';

        const existing = document.getElementById('entry-list-' + e.id);
        const item = document.createElement('div');
        item.className = 'entry-list-item';
        item.id = 'entry-list-' + e.id;
        item.style.cssText = 'display:flex;gap:.75rem;padding:.75rem 1.25rem;border-bottom:1px solid var(--border);align-items:flex-start;cursor:pointer;';
        item.onclick = () => openEditModalById(e.id);
        item.innerHTML = `
            <div style="width:4px;border-radius:4px;flex-shrink:0;align-self:stretch;background:var(--primary);"></div>
            <div style="flex:1;min-width:0;">
                <div style="font-size:.8375rem;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${htmlEsc(e.title)}</div>
                <div style="font-size:.75rem;color:var(--text-muted);margin-top:.1rem;">${e.start_time} - ${e.end_time}</div>
            </div>
            <div style="font-size:.75rem;font-weight:700;color:var(--text-secondary);flex-shrink:0;">${e.formatted_duration}</div>`;

        if (existing) {
            listEl.replaceChild(item, existing);
        } else {
            listEl.appendChild(item);
        }
    }

    function removeEntryFromUI(id) {
        document.getElementById('entry-' + id)?.remove();
        document.getElementById('entry-list-' + id)?.remove();
        delete entries[id];
        entryCount--;
        const noMsg = document.getElementById('noEntriesMsg');
        if (noMsg && entryCount === 0) noMsg.style.display = '';
    }

    function updateTotals(mins) {
        totalMin = mins;
        const h  = Math.floor(mins / 60);
        const m  = mins % 60;
        const str = h + 'h ' + String(m).padStart(2,'0') + 'm';
        const el1 = document.getElementById('totalHoursLabel');
        const el2 = document.getElementById('sidebarTotal');
        if (el1) el1.textContent = str + ' logged';
        if (el2) el2.textContent = str;
        const ec = document.getElementById('entriesCount');
        if (ec) ec.textContent = entryCount;
    }

